#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[250010],mp1[250010];
long long id[250010],f[250010],w[250010],ansmax,ansmin,anssum,a[250010],b[250010],min1[250010],max1[250010],dfn[250010],flag[250010],cnt[250010],g[250010],dfncnt,fa[250010][21],dis[250010],d[250010],lg[250010];
void dfs(long long x,long long f=0)
{
    dfn[x]=++dfncnt;
    fa[x][0]=f;
    d[x]=d[f]+1;
    for(long long i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=f)
        {
            id[v]=val;
            dis[v]=dis[x]+1;
            dfs(v,x);
        }
    }
}
long long lca(long long x,long long y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(long long i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
long long dist(long long x,long long y)
{
    return dis[x]+dis[y]-dis[lca(x,y)]*2;
}
bool cmp(long long x,long long y)
{
    return dfn[x]<dfn[y];
}
void dfs2(long long x,long long fa=-1)
{
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=fa)
        {
            dfs2(v,x);
            w[x]+=w[v];
        }
    }
}
int main()
{
    long long n,m,t;
    scanf("%lld%lld%lld",&n,&m,&t);
    for(long long i=2;i<=n;i++)
    {
        lg[i]=lg[i/2]+1;
    }
    for(long long i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back({v,i});
        mp[v].push_back({u,i});
    }
    dfs(1);
    while(m--)
    {
        long long k;
        scanf("%lld",&k);
        for(long long i=1;i<=k;i++)
        {
            scanf("%lld",&a[i]);
        }
        sort(a+1,a+1+k,cmp);
        long long tot=0;
        for(long long i=1;i<k;i++)
        {
            b[++tot]=a[i];
            b[++tot]=lca(a[i],a[i+1]);
        }
        b[++tot]=a[k];
        // b[++tot]=1;
        sort(b+1,b+1+tot);
        tot=unique(b+1,b+1+tot)-b-1;
        sort(b+1,b+1+tot,cmp);
        for(long long i=1;i<tot;i++)
        {
            long long l=lca(b[i],b[i+1]);
            w[b[i+1]]++;
            w[l]--;
        }
    }
    dfs2(1);
    vector<int> ans;
    for(int i=1;i<=n;i++)
    {
        if(w[i]>=t)
        {
            ans.push_back(id[i]);
        }
    }
    sort(ans.begin(),ans.end());
    printf("%d\n",ans.size());
    for(int i:ans)
    {
        printf("%d ",i);
    }
    return 0;
}
